    let currentMaxLeft = Number.NEGATIVE_INFINITY;
    for (let i = 0; i < N; i++) {
        PMax[i] = currentMaxLeft;
        currentMaxLeft = Math.max(currentMaxLeft, nums[i]);
    }

    // 2. Calculate Suffix Maximums (SMax[i] = max(nums[i+1]...nums[N-1]))
    const SMax = new Array(N);
    let currentMaxRight = Number.NEGATIVE_INFINITY;
    for (let i = N - 1; i >= 0; i--) {
        SMax[i] = currentMaxRight;
        currentMaxRight = Math.max(currentMaxRight, nums[i]);
